/* SQL text to drop default existing default constraints in entity __mj.ScheduledAction */

DO $$
DECLARE
   v_constraint_name TEXT;
BEGIN
   SELECT con.conname INTO v_constraint_name
   FROM pg_catalog.pg_constraint con
   JOIN pg_catalog.pg_class rel ON rel.oid = con.conrelid
   JOIN pg_catalog.pg_namespace nsp ON nsp.oid = rel.relnamespace
   JOIN pg_catalog.pg_attribute att ON att.attrelid = rel.oid AND att.attnum = ANY(con.conkey)
   WHERE nsp.nspname = '__mj'
     AND rel.relname = 'ScheduledAction'
     AND att.attname = '__mj_CreatedAt'
     AND con.contype = 'c';

   IF v_constraint_name IS NOT NULL THEN
      EXECUTE format('ALTER TABLE %I.%I DROP CONSTRAINT %I', '__mj', 'ScheduledAction', v_constraint_name);
   END IF;

   -- Also drop any column default
   ALTER TABLE __mj."ScheduledAction" ALTER COLUMN "__mj_CreatedAt" DROP DEFAULT;
END $$;

/* SQL text to add default constraint for special date field __mj_CreatedAt in entity __mj.ScheduledAction */
ALTER TABLE __mj."ScheduledAction" ALTER COLUMN "__mj_CreatedAt" SET DEFAULT (NOW() AT TIME ZONE 'UTC');

