DROP VIEW IF EXISTS __mj."vwActionCategories" CASCADE;
CREATE VIEW __mj."vwActionCategories"
AS
SELECT
    a.*,
    MJActionCategory_ParentID."Name" AS "Parent",
    root_ParentID.root_id AS "RootParentID"
FROM
    __mj."ActionCategory" AS a
LEFT OUTER JOIN
    __mj."ActionCategory" AS MJActionCategory_ParentID
  ON
    "a"."ParentID" = MJActionCategory_ParentID."ID"

LEFT JOIN LATERAL (
    SELECT __mj."fn_action_category_parent_id_get_root_id"(a."ID", a."ParentID") AS root_id
) AS root_ParentID ON true
;
