    p_step_type text DEFAULT NULL,
    p_starting_step BOOLEAN DEFAULT NULL,
    p_timeout_seconds_clear boolean DEFAULT FALSE,
    p_timeout_seconds integer DEFAULT NULL,
    p_retry_count integer DEFAULT NULL,
    p_on_error_behavior text DEFAULT NULL,
    p_action_id uuid DEFAULT NULL,
    p_sub_agent_id uuid DEFAULT NULL,
