    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."AIAgentStep"
        (
            "ID",
            "AgentID",
                "Name",
                "Description",
                "StepType",
                "StartingStep",
                "TimeoutSeconds",
                "RetryCount",
                "OnErrorBehavior",
                "ActionID",
