DROP VIEW IF EXISTS __mj."vwAIPromptCategories" CASCADE;
CREATE VIEW __mj."vwAIPromptCategories"
AS
SELECT
    a.*,
    MJAIPromptCategory_ParentID."Name" AS "Parent",
    root_ParentID.root_id AS "RootParentID"
FROM
    __mj."AIPromptCategory" AS a
LEFT OUTER JOIN
    __mj."AIPromptCategory" AS MJAIPromptCategory_ParentID
  ON
    "a"."ParentID" = MJAIPromptCategory_ParentID."ID"

LEFT JOIN LATERAL (
    SELECT __mj."fn_ai_prompt_category_parent_id_get_root_id"(a."ID", a."ParentID") AS root_id
) AS root_ParentID ON true
;
