CREATE OR REPLACE FUNCTION __mj."fn_create_ai_prompt_model"(
    p_id uuid DEFAULT NULL,
    p_prompt_id uuid DEFAULT NULL,
    p_model_id uuid DEFAULT NULL,
    p_vendor_id uuid DEFAULT NULL,
    p_configuration_id uuid DEFAULT NULL,
    p_priority integer DEFAULT NULL,
    p_execution_group integer DEFAULT NULL,
    p_model_parameters text DEFAULT NULL,
    p_status text DEFAULT NULL,
    p_parallelization_mode text DEFAULT NULL,
    p_parallel_count integer DEFAULT NULL,
    p_parallel_config_param text DEFAULT NULL,
    p_effort_level integer DEFAULT NULL
) RETURNS SETOF __mj."vwAIPromptModels" AS $$
DECLARE
    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."AIPromptModel"
        (
            "ID",
            "PromptID",
                "ModelID",
                "VendorID",
                "ConfigurationID",
                "Priority",
                "ExecutionGroup",
                "ModelParameters",
                "Status",
                "ParallelizationMode",
                "ParallelCount",
                "ParallelConfigParam",
                "EffortLevel"
        )
    VALUES
        (
            v_new_id,
            p_prompt_id,
                p_model_id,
                p_vendor_id,
                p_configuration_id,
                COALESCE(p_priority, 0),
                COALESCE(p_execution_group, 0),
                p_model_parameters,
                COALESCE(p_status, 'Active'),
                COALESCE(p_parallelization_mode, 'None'),
                COALESCE(p_parallel_count, 1),
                p_parallel_config_param,
                p_effort_level
        )
    ;

    RETURN QUERY
    SELECT * FROM __mj."vwAIPromptModels"
    WHERE "ID" = v_new_id;
END;
$$ LANGUAGE plpgsql;
GRANT EXECUTE ON FUNCTION __mj."fn_create_ai_prompt_model" TO "cdp_Developer";
GRANT EXECUTE ON FUNCTION __mj."fn_create_ai_prompt_model" TO "cdp_Integration";

