DROP VIEW IF EXISTS __mj."vwAPIScopes" CASCADE;
CREATE VIEW __mj."vwAPIScopes"
AS
SELECT
    a.*,
    MJAPIScope_ParentID."Name" AS "Parent",
    root_ParentID.root_id AS "RootParentID"
FROM
    __mj."APIScope" AS a
LEFT OUTER JOIN
    __mj."APIScope" AS MJAPIScope_ParentID
  ON
    "a"."ParentID" = MJAPIScope_ParentID."ID"

LEFT JOIN LATERAL (
    SELECT __mj."fn_api_scope_parent_id_get_root_id"(a."ID", a."ParentID") AS root_id
) AS root_ParentID ON true
;
