CREATE OR REPLACE FUNCTION __mj."fn_create_api_key_usage_log"(
    p_id uuid DEFAULT NULL,
    p_api_key_id uuid DEFAULT NULL,
    p_endpoint text DEFAULT NULL,
    p_operation text DEFAULT NULL,
    p_method text DEFAULT NULL,
    p_status_code integer DEFAULT NULL,
    p_response_time_ms integer DEFAULT NULL,
    p_ip_address text DEFAULT NULL,
    p_user_agent text DEFAULT NULL,
    p_application_id uuid DEFAULT NULL,
    p_requested_resource text DEFAULT NULL,
    p_scopes_evaluated text DEFAULT NULL,
    p_authorization_result text DEFAULT NULL,
    p_denied_reason text DEFAULT NULL
) RETURNS SETOF __mj."vwAPIKeyUsageLogs" AS $$
DECLARE
    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."APIKeyUsageLog"
        (
            "ID",
            "APIKeyID",
                "Endpoint",
                "Operation",
                "Method",
                "StatusCode",
                "ResponseTimeMs",
                "IPAddress",
                "UserAgent",
                "ApplicationID",
                "RequestedResource",
                "ScopesEvaluated",
                "AuthorizationResult",
                "DeniedReason"
        )
    VALUES
        (
            v_new_id,
            p_api_key_id,
                p_endpoint,
                p_operation,
                p_method,
                p_status_code,
                p_response_time_ms,
                p_ip_address,
                p_user_agent,
                p_application_id,
                p_requested_resource,
                p_scopes_evaluated,
                COALESCE(p_authorization_result, 'Allowed'),
                p_denied_reason
        )
    ;

    RETURN QUERY
    SELECT * FROM __mj."vwAPIKeyUsageLogs"
    WHERE "ID" = v_new_id;
END;
$$ LANGUAGE plpgsql;
