AS
SELECT
    a.*,
    MJAuditLogType_ParentID."Name" AS "Parent",
    MJAuthorization_AuthorizationID."Name" AS "Authorization",
    root_ParentID.root_id AS "RootParentID"
FROM
    __mj."AuditLogType" AS a
LEFT OUTER JOIN
    __mj."AuditLogType" AS MJAuditLogType_ParentID
  ON
