  ON
    "a"."AuthorizationID" = MJAuthorization_AuthorizationID."ID"

LEFT JOIN LATERAL (
    SELECT __mj."fn_audit_log_type_parent_id_get_root_id"(a."ID", a."ParentID") AS root_id
) AS root_ParentID ON true
;
