    p_content_item_aid uuid DEFAULT NULL,
    p_content_item_bid uuid DEFAULT NULL,
    p_similarity_score decimal(5, 4) DEFAULT NULL,
    p_detection_method text DEFAULT NULL,
    p_status text DEFAULT NULL,
