    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."ContentItemDuplicate"
        (
            "ID",
            "ContentItemAID",
                "ContentItemBID",
                "SimilarityScore",
                "DetectionMethod",
                "Status",
                "ResolvedByUserID",
                "ResolvedAt",
                "Resolution"
        )
    VALUES
        (
            v_new_id,
            p_content_item_aid,
                p_content_item_bid,
                p_similarity_score,
                COALESCE(p_detection_method, 'Checksum'),
                COALESCE(p_status, 'Pending'),
                p_resolved_by_user_id,
                p_resolved_at,
                p_resolution
        )
    ;

    RETURN QUERY
    SELECT * FROM __mj."vwContentItemDuplicates"
    WHERE "ID" = v_new_id;
END;
$$ LANGUAGE plpgsql;
