CREATE OR REPLACE FUNCTION __mj."fn_delete_dashboard"(
    p_id uuid
) RETURNS TABLE("ID" uuid) AS $$
#variable_conflict use_column
DECLARE
    v_affected_count INTEGER;
    v_rec RECORD;
BEGIN
    -- Cascade: Delete MJ: Dashboard Category Links records via DashboardID
    FOR v_rec IN
        SELECT "ID"
        FROM __mj."DashboardCategoryLink"
        WHERE "DashboardID" = p_id
    LOOP
        PERFORM __mj."fn_delete_dashboard_category_link"(v_rec."ID");
    END LOOP;

        -- Cascade: Delete MJ: Dashboard Permissions records via DashboardID
    FOR v_rec IN
        SELECT "ID"
        FROM __mj."DashboardPermission"
        WHERE "DashboardID" = p_id
    LOOP
        PERFORM __mj."fn_delete_dashboard_permission"(v_rec."ID");
    END LOOP;

        -- Cascade: Delete MJ: Dashboard User Preferences records via DashboardID
    FOR v_rec IN
        SELECT "ID"
        FROM __mj."DashboardUserPreference"
        WHERE "DashboardID" = p_id
    LOOP
        PERFORM __mj."fn_delete_dashboard_user_preference"(v_rec."ID");
    END LOOP;

        -- Cascade: Delete MJ: Dashboard User States records via DashboardID
    FOR v_rec IN
        SELECT "ID"
        FROM __mj."DashboardUserState"
        WHERE "DashboardID" = p_id
    LOOP
        PERFORM __mj."fn_delete_dashboard_user_state"(v_rec."ID");
    END LOOP;

    
    DELETE FROM __mj."Dashboard"
    WHERE "ID" = p_id;

    GET DIAGNOSTICS v_affected_count = ROW_COUNT;

    IF v_affected_count = 0 THEN
        RETURN QUERY SELECT NULL::uuid AS "ID";
    ELSE
        RETURN QUERY SELECT p_id AS "ID";
    END IF;
END;
$$ LANGUAGE plpgsql;
