CREATE OR REPLACE FUNCTION __mj."fn_create_duplicate_run"(
    p_id uuid DEFAULT NULL,
    p_entity_id uuid DEFAULT NULL,
    p_started_by_user_id uuid DEFAULT NULL,
    p_source_list_id uuid DEFAULT NULL,
    p_started_at TIMESTAMPTZ DEFAULT NULL,
    p_ended_at TIMESTAMPTZ DEFAULT NULL,
    p_approval_status text DEFAULT NULL,
    p_approval_comments text DEFAULT NULL,
    p_approved_by_user_id uuid DEFAULT NULL,
    p_processing_status text DEFAULT NULL,
    p_processing_error_message text DEFAULT NULL,
    p_total_item_count integer DEFAULT NULL,
    p_processed_item_count_clear boolean DEFAULT FALSE,
    p_processed_item_count integer DEFAULT NULL,
    p_last_processed_offset_clear boolean DEFAULT FALSE,
    p_last_processed_offset integer DEFAULT NULL,
    p_batch_size_clear boolean DEFAULT FALSE,
    p_batch_size integer DEFAULT NULL,
    p_cancellation_requested boolean DEFAULT NULL
) RETURNS SETOF __mj."vwDuplicateRuns" AS $$
DECLARE
    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."DuplicateRun"
        (
            "ID",
            "EntityID",
                "StartedByUserID",
                "SourceListID",
                "StartedAt",
                "EndedAt",
                "ApprovalStatus",
                "ApprovalComments",
                "ApprovedByUserID",
                "ProcessingStatus",
                "ProcessingErrorMessage",
                "TotalItemCount",
                "ProcessedItemCount",
                "LastProcessedOffset",
                "BatchSize",
                "CancellationRequested"
        )
    VALUES
        (
            v_new_id,
            p_entity_id,
                p_started_by_user_id,
                p_source_list_id,
                COALESCE(p_started_at, NOW()),
                p_ended_at,
                COALESCE(p_approval_status, 'Pending'),
                p_approval_comments,
                p_approved_by_user_id,
                COALESCE(p_processing_status, 'Pending'),
                p_processing_error_message,
                p_total_item_count,
                CASE WHEN p_processed_item_count_clear = true THEN NULL ELSE COALESCE(p_processed_item_count, 0) END,
                CASE WHEN p_last_processed_offset_clear = true THEN NULL ELSE COALESCE(p_last_processed_offset, 0) END,
                CASE WHEN p_batch_size_clear = true THEN NULL ELSE COALESCE(p_batch_size, 100) END,
                COALESCE(p_cancellation_requested, FALSE)
        )
    ;

    RETURN QUERY
    SELECT * FROM __mj."vwDuplicateRuns"
    WHERE "ID" = v_new_id;
END;
$$ LANGUAGE plpgsql;
