    "g"."GeneratedByModelID" = MJAIModel_GeneratedByModelID."ID"
LEFT OUTER JOIN
    __mj."Entity" AS MJEntity_LinkedEntityID
  ON
    "g"."LinkedEntityID" = MJEntity_LinkedEntityID."ID"
;
