CREATE OR REPLACE FUNCTION __mj."fn_create_integration_object"(
    p_id uuid DEFAULT NULL,
    p_integration_id uuid DEFAULT NULL,
    p_name text DEFAULT NULL,
    p_display_name text DEFAULT NULL,
    p_description text DEFAULT NULL,
    p_category text DEFAULT NULL,
    p_api_path text DEFAULT NULL,
    p_response_data_key text DEFAULT NULL,
    p_default_page_size integer DEFAULT NULL,
    p_supports_pagination boolean DEFAULT NULL,
    p_pagination_type text DEFAULT NULL,
    p_supports_incremental_sync boolean DEFAULT NULL,
    p_supports_write boolean DEFAULT NULL,
    p_default_query_params text DEFAULT NULL,
    p_configuration text DEFAULT NULL,
    p_sequence integer DEFAULT NULL,
    p_status text DEFAULT NULL,
    p_write_api_path text DEFAULT NULL,
    p_write_method_clear boolean DEFAULT FALSE,
    p_write_method text DEFAULT NULL,
    p_delete_method_clear boolean DEFAULT FALSE,
    p_delete_method text DEFAULT NULL,
    p_is_custom boolean DEFAULT NULL
) RETURNS SETOF __mj."vwIntegrationObjects" AS $$
DECLARE
    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."IntegrationObject"
        (
            "ID",
            "IntegrationID",
                "Name",
                "DisplayName",
                "Description",
                "Category",
                "APIPath",
                "ResponseDataKey",
                "DefaultPageSize",
                "SupportsPagination",
                "PaginationType",
                "SupportsIncrementalSync",
                "SupportsWrite",
                "DefaultQueryParams",
                "Configuration",
                "Sequence",
                "Status",
                "WriteAPIPath",
                "WriteMethod",
                "DeleteMethod",
                "IsCustom"
        )
    VALUES
        (
            v_new_id,
            p_integration_id,
                p_name,
                p_display_name,
                p_description,
                p_category,
                p_api_path,
                p_response_data_key,
                COALESCE(p_default_page_size, 100),
                COALESCE(p_supports_pagination, TRUE),
                COALESCE(p_pagination_type, 'PageNumber'),
                COALESCE(p_supports_incremental_sync, FALSE),
                COALESCE(p_supports_write, FALSE),
                p_default_query_params,
                p_configuration,
                COALESCE(p_sequence, 0),
                COALESCE(p_status, 'Active'),
                p_write_api_path,
                CASE WHEN p_write_method_clear = true THEN NULL ELSE COALESCE(p_write_method, 'POST') END,
                CASE WHEN p_delete_method_clear = true THEN NULL ELSE COALESCE(p_delete_method, 'DELETE') END,
                COALESCE(p_is_custom, FALSE)
        )
    ;

    RETURN QUERY
    SELECT * FROM __mj."vwIntegrationObjects"
    WHERE "ID" = v_new_id;
END;
$$ LANGUAGE plpgsql;
