------------------------------------------------------------
----- BASE VIEW FOR ENTITY:      MJ: List Categories
-----               SCHEMA:      __mj
-----               BASE TABLE:  ListCategory
-----               PRIMARY KEY: ID
------------------------------------------------------------
DROP VIEW IF EXISTS __mj."vwListCategories" CASCADE;
CREATE VIEW __mj."vwListCategories"
AS
SELECT
    l.*,
    MJListCategory_ParentID."Name" AS "Parent",
    MJUser_UserID."Name" AS "User",
    root_ParentID.root_id AS "RootParentID"
FROM
    __mj."ListCategory" AS l
LEFT OUTER JOIN
    __mj."ListCategory" AS MJListCategory_ParentID
  ON
    "l"."ParentID" = MJListCategory_ParentID."ID"
INNER JOIN
    __mj."User" AS MJUser_UserID
  ON
    "l"."UserID" = MJUser_UserID."ID"

LEFT JOIN LATERAL (
    SELECT __mj."fn_list_category_parent_id_get_root_id"(l."ID", l."ParentID") AS root_id
) AS root_ParentID ON true
;
