    p_mcp_server_id uuid DEFAULT NULL,
    p_name text DEFAULT NULL,
    p_description text DEFAULT NULL,
    p_credential_id uuid DEFAULT NULL,
    p_custom_header_name text DEFAULT NULL,
    p_company_id uuid DEFAULT NULL,
    p_status text DEFAULT NULL,
    p_auto_sync_tools BOOLEAN DEFAULT NULL,
    p_auto_generate_actions BOOLEAN DEFAULT NULL,
    p_log_tool_calls BOOLEAN DEFAULT NULL,
    p_log_input_parameters BOOLEAN DEFAULT NULL,
    p_log_output_content BOOLEAN DEFAULT NULL,
    p_max_output_log_size_clear boolean DEFAULT FALSE,
    p_max_output_log_size integer DEFAULT NULL,
    p_last_connected_at TIMESTAMPTZ DEFAULT NULL,
    p_last_error_message text DEFAULT NULL,
    p_environment_vars text DEFAULT NULL
) RETURNS SETOF __mj."vwMCPServerConnections" AS $$
DECLARE
    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."MCPServerConnection"
        (
            "ID",
            "MCPServerID",
                "Name",
                "Description",
                "CredentialID",
                "CustomHeaderName",
                "CompanyID",
                "Status",
                "AutoSyncTools",
                "AutoGenerateActions",
                "LogToolCalls",
                "LogInputParameters",
                "LogOutputContent",
                "MaxOutputLogSize",
                "LastConnectedAt",
                "LastErrorMessage",
                "EnvironmentVars"
        )
    VALUES
        (
            v_new_id,
            p_mcp_server_id,
                p_name,
                p_description,
                p_credential_id,
