                COALESCE(p_auto_sync_tools, TRUE),
                COALESCE(p_auto_generate_actions, FALSE),
                COALESCE(p_log_tool_calls, TRUE),
                COALESCE(p_log_input_parameters, TRUE),
                COALESCE(p_log_output_content, TRUE),
                CASE WHEN p_max_output_log_size_clear = true THEN NULL ELSE COALESCE(p_max_output_log_size, 102400) END,
                p_last_connected_at,
                p_last_error_message,
                p_environment_vars
        )
    ;

