CREATE OR REPLACE FUNCTION __mj."fn_create_mcp_server"(
    p_id uuid DEFAULT NULL,
    p_name text DEFAULT NULL,
    p_description text DEFAULT NULL,
    p_server_url text DEFAULT NULL,
    p_command text DEFAULT NULL,
    p_command_args text DEFAULT NULL,
    p_transport_type text DEFAULT NULL,
    p_default_auth_type text DEFAULT NULL,
    p_credential_type_id uuid DEFAULT NULL,
    p_status text DEFAULT NULL,
    p_last_sync_at TIMESTAMPTZ DEFAULT NULL,
    p_rate_limit_per_minute integer DEFAULT NULL,
    p_rate_limit_per_hour integer DEFAULT NULL,
    p_connection_timeout_ms_clear boolean DEFAULT FALSE,
    p_connection_timeout_ms integer DEFAULT NULL,
    p_request_timeout_ms_clear boolean DEFAULT FALSE,
    p_request_timeout_ms integer DEFAULT NULL,
    p_documentation_url text DEFAULT NULL,
    p_icon_class text DEFAULT NULL,
    p_o_auth_issuer_url text DEFAULT NULL,
    p_o_auth_scopes text DEFAULT NULL,
    p_o_auth_metadata_cache_ttl_minutes_clear boolean DEFAULT FALSE,
    p_o_auth_metadata_cache_ttl_minutes integer DEFAULT NULL,
    p_o_auth_client_id text DEFAULT NULL,
    p_o_auth_client_secret_encrypted text DEFAULT NULL,
    p_o_auth_require_pkce BOOLEAN DEFAULT NULL
) RETURNS SETOF __mj."vwMCPServers" AS $$
DECLARE
    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."MCPServer"
        (
            "ID",
            "Name",
                "Description",
                "ServerURL",
                "Command",
                "CommandArgs",
                "TransportType",
                "DefaultAuthType",
                "CredentialTypeID",
                "Status",
                "LastSyncAt",
                "RateLimitPerMinute",
                "RateLimitPerHour",
                "ConnectionTimeoutMs",
                "RequestTimeoutMs",
                "DocumentationURL",
                "IconClass",
                "OAuthIssuerURL",
                "OAuthScopes",
                "OAuthMetadataCacheTTLMinutes",
                "OAuthClientID",
                "OAuthClientSecretEncrypted",
                "OAuthRequirePKCE"
        )
    VALUES
        (
            v_new_id,
            p_name,
                p_description,
                p_server_url,
                p_command,
                p_command_args,
                p_transport_type,
                p_default_auth_type,
                p_credential_type_id,
                COALESCE(p_status, 'Active'),
                p_last_sync_at,
                p_rate_limit_per_minute,
                p_rate_limit_per_hour,
                CASE WHEN p_connection_timeout_ms_clear = true THEN NULL ELSE COALESCE(p_connection_timeout_ms, 30000) END,
                CASE WHEN p_request_timeout_ms_clear = true THEN NULL ELSE COALESCE(p_request_timeout_ms, 60000) END,
                p_documentation_url,
                p_icon_class,
                p_o_auth_issuer_url,
                p_o_auth_scopes,
                CASE WHEN p_o_auth_metadata_cache_ttl_minutes_clear = true THEN NULL ELSE COALESCE(p_o_auth_metadata_cache_ttl_minutes, 1440) END,
                p_o_auth_client_id,
                p_o_auth_client_secret_encrypted,
                COALESCE(p_o_auth_require_pkce, TRUE)
        )
    ;

    RETURN QUERY
    SELECT * FROM __mj."vwMCPServers"
    WHERE "ID" = v_new_id;
END;
$$ LANGUAGE plpgsql;
