CREATE OR REPLACE FUNCTION __mj."fn_delete_report"(
    p_id uuid
) RETURNS TABLE("ID" uuid) AS $$
#variable_conflict use_column
DECLARE
    v_affected_count INTEGER;
    v_rec RECORD;
BEGIN
    -- Cascade: Delete MJ: Report Snapshots records via ReportID
    FOR v_rec IN
        SELECT "ID"
        FROM __mj."ReportSnapshot"
        WHERE "ReportID" = p_id
    LOOP
        PERFORM __mj."fn_delete_report_snapshot"(v_rec."ID");
    END LOOP;

        -- Cascade: Delete MJ: Report User States records via ReportID
    FOR v_rec IN
        SELECT "ID"
        FROM __mj."ReportUserState"
        WHERE "ReportID" = p_id
    LOOP
        PERFORM __mj."fn_delete_report_user_state"(v_rec."ID");
    END LOOP;

        -- Cascade: Delete MJ: Report Versions records via ReportID
    FOR v_rec IN
        SELECT "ID"
        FROM __mj."ReportVersion"
        WHERE "ReportID" = p_id
    LOOP
        PERFORM __mj."fn_delete_report_version"(v_rec."ID");
    END LOOP;

    
    DELETE FROM __mj."Report"
    WHERE "ID" = p_id;

    GET DIAGNOSTICS v_affected_count = ROW_COUNT;

    IF v_affected_count = 0 THEN
        RETURN QUERY SELECT NULL::uuid AS "ID";
    ELSE
        RETURN QUERY SELECT p_id AS "ID";
    END IF;
END;
$$ LANGUAGE plpgsql;
