CREATE OR REPLACE FUNCTION __mj."fn_create_scheduled_job"(
    p_id uuid DEFAULT NULL,
    p_job_type_id uuid DEFAULT NULL,
    p_name text DEFAULT NULL,
    p_description text DEFAULT NULL,
    p_cron_expression text DEFAULT NULL,
    p_timezone text DEFAULT NULL,
    p_start_at TIMESTAMPTZ DEFAULT NULL,
    p_end_at TIMESTAMPTZ DEFAULT NULL,
    p_status text DEFAULT NULL,
    p_configuration text DEFAULT NULL,
    p_owner_user_id uuid DEFAULT NULL,
    p_last_run_at TIMESTAMPTZ DEFAULT NULL,
    p_next_run_at TIMESTAMPTZ DEFAULT NULL,
    p_run_count integer DEFAULT NULL,
    p_success_count integer DEFAULT NULL,
    p_failure_count integer DEFAULT NULL,
    p_notify_on_success BOOLEAN DEFAULT NULL,
    p_notify_on_failure BOOLEAN DEFAULT NULL,
    p_notify_user_id uuid DEFAULT NULL,
    p_notify_via_email BOOLEAN DEFAULT NULL,
    p_notify_via_in_app BOOLEAN DEFAULT NULL,
    p_lock_token uuid DEFAULT NULL,
    p_locked_at TIMESTAMPTZ DEFAULT NULL,
    p_locked_by_instance text DEFAULT NULL,
    p_expected_completion_at TIMESTAMPTZ DEFAULT NULL,
    p_concurrency_mode text DEFAULT NULL
) RETURNS SETOF __mj."vwScheduledJobs" AS $$
DECLARE
    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."ScheduledJob"
        (
            "ID",
            "JobTypeID",
                "Name",
                "Description",
                "CronExpression",
                "Timezone",
                "StartAt",
                "EndAt",
                "Status",
                "Configuration",
                "OwnerUserID",
                "LastRunAt",
                "NextRunAt",
                "RunCount",
                "SuccessCount",
                "FailureCount",
                "NotifyOnSuccess",
                "NotifyOnFailure",
                "NotifyUserID",
                "NotifyViaEmail",
                "NotifyViaInApp",
                "LockToken",
                "LockedAt",
                "LockedByInstance",
                "ExpectedCompletionAt",
                "ConcurrencyMode"
        )
    VALUES
        (
            v_new_id,
            p_job_type_id,
                p_name,
                p_description,
                p_cron_expression,
                COALESCE(p_timezone, 'UTC'),
                p_start_at,
                p_end_at,
                COALESCE(p_status, 'Pending'),
                p_configuration,
                p_owner_user_id,
                p_last_run_at,
                p_next_run_at,
                COALESCE(p_run_count, 0),
                COALESCE(p_success_count, 0),
                COALESCE(p_failure_count, 0),
                COALESCE(p_notify_on_success, FALSE),
                COALESCE(p_notify_on_failure, TRUE),
                p_notify_user_id,
                COALESCE(p_notify_via_email, FALSE),
                COALESCE(p_notify_via_in_app, TRUE),
                p_lock_token,
                p_locked_at,
                p_locked_by_instance,
                p_expected_completion_at,
                COALESCE(p_concurrency_mode, 'Skip')
        )
    ;

    RETURN QUERY
    SELECT * FROM __mj."vwScheduledJobs"
    WHERE "ID" = v_new_id;
END;
$$ LANGUAGE plpgsql;
