------------------------------------------------------------
----- BASE VIEW FOR ENTITY:      MJ: Skills
-----               SCHEMA:      __mj
-----               BASE TABLE:  Skill
-----               PRIMARY KEY: ID
------------------------------------------------------------
DROP VIEW IF EXISTS __mj."vwSkills" CASCADE;
CREATE VIEW __mj."vwSkills"
AS
SELECT
    s.*,
    MJSkill_ParentID."Name" AS "Parent",
    root_ParentID.root_id AS "RootParentID"
FROM
    __mj."Skill" AS s
LEFT OUTER JOIN
    __mj."Skill" AS MJSkill_ParentID
  ON
    "s"."ParentID" = MJSkill_ParentID."ID"

LEFT JOIN LATERAL (
    SELECT __mj."fn_skill_parent_id_get_root_id"(s."ID", s."ParentID") AS root_id
) AS root_ParentID ON true
;
