CREATE VIEW __mj."vwTags"
AS
SELECT
    t.*,
    MJTag_ParentID."Name" AS "Parent",
    MJTag_MergedIntoTagID."Name" AS "MergedIntoTag",
    MJAIModel_EmbeddingModelID."Name" AS "EmbeddingModel",
    root_ParentID.root_id AS "RootParentID",
    root_MergedIntoTagID.root_id AS "RootMergedIntoTagID"
FROM
    __mj."Tag" AS t
LEFT OUTER JOIN
    __mj."Tag" AS MJTag_ParentID
  ON
    "t"."ParentID" = MJTag_ParentID."ID"
LEFT OUTER JOIN
    __mj."Tag" AS MJTag_MergedIntoTagID
  ON
    "t"."MergedIntoTagID" = MJTag_MergedIntoTagID."ID"
LEFT OUTER JOIN
    __mj."AIModel" AS MJAIModel_EmbeddingModelID
  ON
    "t"."EmbeddingModelID" = MJAIModel_EmbeddingModelID."ID"

LEFT JOIN LATERAL (
    SELECT __mj."fn_tag_parent_id_get_root_id"(t."ID", t."ParentID") AS root_id
) AS root_ParentID ON true
LEFT JOIN LATERAL (
    SELECT __mj."fn_tag_merged_into_tag_id_get_root_id"(t."ID", t."MergedIntoTagID") AS root_id
) AS root_MergedIntoTagID ON true
;
