-----               PRIMARY KEY: ID
------------------------------------------------------------
DROP VIEW IF EXISTS __mj."vwTestSuites" CASCADE;
CREATE VIEW __mj."vwTestSuites"
AS
SELECT
    t.*,
    MJTestSuite_ParentID."Name" AS "Parent",
    root_ParentID.root_id AS "RootParentID"
FROM
    __mj."TestSuite" AS t
LEFT OUTER JOIN
    __mj."TestSuite" AS MJTestSuite_ParentID
  ON
    "t"."ParentID" = MJTestSuite_ParentID."ID"

LEFT JOIN LATERAL (
    SELECT __mj."fn_test_suite_parent_id_get_root_id"(t."ID", t."ParentID") AS root_id
) AS root_ParentID ON true
;
