                p_default_prompt_effort_level,
                p_chat_handling_option,
                p_default_artifact_type_id,
                COALESCE(p_owner_user_id, 'ECAFCCEC-6A37-EF11-86D4-000D3A4E707E'),
                COALESCE(p_invocation_mode, 'Any'),
                COALESCE(p_artifact_creation_mode, 'Always'),
