                COALESCE(p_example_injection_strategy, 'Semantic'),
                COALESCE(p_is_restricted, FALSE),
                COALESCE(p_message_mode, 'None'),
                p_max_messages,
                p_attachment_storage_provider_id,
                p_attachment_root_path,
                p_inline_storage_threshold_bytes,
                p_agent_type_prompt_params,
                p_scope_config,
                CASE WHEN p_note_retention_days_clear = true THEN NULL ELSE COALESCE(p_note_retention_days, 90) END,
                CASE WHEN p_example_retention_days_clear = true THEN NULL ELSE COALESCE(p_example_retention_days, 180) END,
                COALESCE(p_auto_archive_enabled, TRUE),
                p_reranker_configuration,
                p_category_id,
                COALESCE(p_allow_ephemeral_client_tools, TRUE),
                p_default_storage_account_id
        )
    ;

    RETURN QUERY
    SELECT * FROM __mj."vwAIAgents"
    WHERE "ID" = v_new_id;
END;
$$ LANGUAGE plpgsql;
