CREATE OR REPLACE FUNCTION __mj."fn_create_ai_configuration"(
    p_id uuid DEFAULT NULL,
    p_name text DEFAULT NULL,
    p_description text DEFAULT NULL,
    p_is_default BOOLEAN DEFAULT NULL,
    p_status text DEFAULT NULL,
    p_default_prompt_for_context_compression_id uuid DEFAULT NULL,
    p_default_prompt_for_context_summarization_id uuid DEFAULT NULL,
    p_default_storage_provider_id uuid DEFAULT NULL,
    p_default_storage_root_path text DEFAULT NULL,
    p_parent_id uuid DEFAULT NULL
) RETURNS SETOF __mj."vwAIConfigurations" AS $$
DECLARE
    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."AIConfiguration"
        (
            "ID",
            "Name",
                "Description",
                "IsDefault",
                "Status",
                "DefaultPromptForContextCompressionID",
                "DefaultPromptForContextSummarizationID",
                "DefaultStorageProviderID",
                "DefaultStorageRootPath",
                "ParentID"
        )
    VALUES
        (
            v_new_id,
            p_name,
                p_description,
                COALESCE(p_is_default, FALSE),
                COALESCE(p_status, 'Active'),
                p_default_prompt_for_context_compression_id,
                p_default_prompt_for_context_summarization_id,
                p_default_storage_provider_id,
                p_default_storage_root_path,
                p_parent_id
        )
    ;

    RETURN QUERY
    SELECT * FROM __mj."vwAIConfigurations"
    WHERE "ID" = v_new_id;
END;
$$ LANGUAGE plpgsql;
