    p_require_specific_models boolean DEFAULT NULL
) RETURNS SETOF __mj."vwAIPrompts" AS $$
DECLARE
    v_new_id uuid;
BEGIN
    v_new_id := COALESCE(p_id, gen_random_uuid());
    INSERT INTO __mj."AIPrompt"
        (
            "ID",
            "Name",
                "Description",
                "TemplateID",
                "CategoryID",
                "TypeID",
                "Status",
                "ResponseFormat",
                "ModelSpecificResponseFormat",
                "AIModelTypeID",
                "MinPowerRank",
                "SelectionStrategy",
                "PowerPreference",
                "ParallelizationMode",
                "ParallelCount",
                "ParallelConfigParam",
                "OutputType",
                "OutputExample",
                "ValidationBehavior",
                "MaxRetries",
                "RetryDelayMS",
                "RetryStrategy",
                "ResultSelectorPromptID",
                "EnableCaching",
                "CacheTTLSeconds",
                "CacheMatchType",
                "CacheSimilarityThreshold",
                "CacheMustMatchModel",
                "CacheMustMatchVendor",
                "CacheMustMatchAgent",
                "CacheMustMatchConfig",
                "PromptRole",
                "PromptPosition",
                "Temperature",
                "TopP",
                "TopK",
                "MinP",
                "FrequencyPenalty",
                "PresencePenalty",
                "Seed",
                "StopSequences",
                "IncludeLogProbs",
                "TopLogProbs",
                "FailoverStrategy",
                "FailoverMaxAttempts",
                "FailoverDelaySeconds",
                "FailoverModelStrategy",
                "FailoverErrorScope",
                "EffortLevel",
                "AssistantPrefill",
                "PrefillFallbackMode",
                "RequireSpecificModels"
        )
    VALUES
        (
            v_new_id,
            p_name,
                p_description,
                p_template_id,
                p_category_id,
                p_type_id,
                p_status,
                COALESCE(p_response_format, 'Any'),
                p_model_specific_response_format,
                p_ai_model_type_id,
                CASE WHEN p_min_power_rank_clear = true THEN NULL ELSE COALESCE(p_min_power_rank, 0) END,
                COALESCE(p_selection_strategy, 'Default'),
                COALESCE(p_power_preference, 'Highest'),
                COALESCE(p_parallelization_mode, 'None'),
                p_parallel_count,
                p_parallel_config_param,
                COALESCE(p_output_type, 'string'),
                p_output_example,
                COALESCE(p_validation_behavior, 'Warn'),
                COALESCE(p_max_retries, 0),
                COALESCE(p_retry_delay_ms, 0),
                COALESCE(p_retry_strategy, 'Fixed'),
                p_result_selector_prompt_id,
                COALESCE(p_enable_caching, FALSE),
                p_cache_ttl_seconds,
                COALESCE(p_cache_match_type, 'Exact'),
                p_cache_similarity_threshold,
                COALESCE(p_cache_must_match_model, TRUE),
                COALESCE(p_cache_must_match_vendor, TRUE),
                COALESCE(p_cache_must_match_agent, FALSE),
                COALESCE(p_cache_must_match_config, FALSE),
                COALESCE(p_prompt_role, 'System'),
                COALESCE(p_prompt_position, 'First'),
                p_temperature,
                p_top_p,
                p_top_k,
                p_min_p,
                p_frequency_penalty,
                p_presence_penalty,
                p_seed,
                p_stop_sequences,
                CASE WHEN p_include_log_probs_clear = true THEN NULL ELSE COALESCE(p_include_log_probs, FALSE) END,
                p_top_log_probs,
                COALESCE(p_failover_strategy, 'SameModelDifferentVendor'),
                CASE WHEN p_failover_max_attempts_clear = true THEN NULL ELSE COALESCE(p_failover_max_attempts, 3) END,
                CASE WHEN p_failover_delay_seconds_clear = true THEN NULL ELSE COALESCE(p_failover_delay_seconds, 5) END,
                COALESCE(p_failover_model_strategy, 'PreferSameModel'),
                COALESCE(p_failover_error_scope, 'All'),
                p_effort_level,
                p_assistant_prefill,
                COALESCE(p_prefill_fallback_mode, 'Ignore'),
                COALESCE(p_require_specific_models, FALSE)
        )
    ;

    RETURN QUERY
    SELECT * FROM __mj."vwAIPrompts"
    WHERE "ID" = v_new_id;
END;
$$ LANGUAGE plpgsql;
